package service

import (
	"testing"
	"strings"
)

func TestShortenURL(t *testing.T) {
	s := NewShortener()
	code, err := s.Shorten("https://example.com/very/long/path")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(code) != 6 {
		t.Errorf("expected code length 6, got %d: %s", len(code), code)
	}
}

func TestShortenEmptyURL(t *testing.T) {
	s := NewShortener()
	_, err := s.Shorten("")
	if err == nil {
		t.Error("expected error for empty URL")
	}
}

func TestResolve(t *testing.T) {
	s := NewShortener()
	code, _ := s.Shorten("https://example.com")
	resolved, err := s.Resolve(code)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if resolved != "https://example.com" {
		t.Errorf("expected https://example.com, got %s", resolved)
	}
}

func TestResolveNotFound(t *testing.T) {
	s := NewShortener()
	_, err := s.Resolve("nonexistent")
	if err == nil {
		t.Error("expected error for unknown code")
	}
	if !strings.Contains(err.Error(), "not found") {
		t.Errorf("expected 'not found' in error, got: %v", err)
	}
}

func TestSamURLSameCode(t *testing.T) {
	s := NewShortener()
	c1, _ := s.Shorten("https://example.com")
	c2, _ := s.Shorten("https://example.com")
	if c1 != c2 {
		t.Errorf("same URL should produce same code, got %s and %s", c1, c2)
	}
}

package service

import (
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"sync"
)

type Shortener struct {
	mu       sync.RWMutex
	urls     map[string]string // code -> url
	reverse  map[string]string // url -> code
}

func NewShortener() *Shortener {
	return &Shortener{
		urls:    make(map[string]string),
		reverse: make(map[string]string),
	}
}

func (s *Shortener) Shorten(url string) (string, error) {
	if url == "" {
		return "", errors.New("url cannot be empty")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if code, exists := s.reverse[url]; exists {
		return code, nil
	}

	hash := sha256.Sum256([]byte(url))
	code := hex.EncodeToString(hash[:])[:6]

	s.urls[code] = url
	s.reverse[url] = code
	return code, nil
}

func (s *Shortener) Resolve(code string) (string, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	url, exists := s.urls[code]
	if !exists {
		return "", errors.New("short URL not found")
	}
	return url, nil
}
